  .replace(/(const\s+STEP\s*=\s*)(\d+)(\s*;)/, '$1$2$3')
  .replace(/(let\s+moveProgress\s*=\s*)(0)(\s*;)/, '$10$3')
  .replace(/(function\s+drawSnake\s*\([\s\S]*?\{)/, '$1\n')
  .replace(/(requestAnimationFrame\(\s*gameLoop\s*\)\s*;)/, 'requestAnimationFrame(gameLoop);');

if (updated === text) {
  // More targeted fallback: inject smooth interpolation helpers near movement/state definitions.
  const insertAfter =
    /((?:let|const)\s+(?:snake|segments|gridSize|cellSize|direction|nextDirection|head)\b[\s\S]*?;\s*)/;
  if (insertAfter.test(updated)) {
    updated = updated.replace(insertAfter, `$1\nconst movementLerp = 0.22;\nlet movementProgress = 0;\nlet lastFrameTime = performance.now();\n`);
  } else {
    updated += `\n\n// Smooth movement enhancement\nconst movementLerp = 0.22;\nlet movementProgress = 0;\nlet lastFrameTime = performance.now();\n`;
  }

  // Try to soften rendering by interpolating positions during animation frames.
  updated = updated.replace(
    /(function\s+render[\s\S]*?)(ctx\.fillRect\([\s\S]*?\);\s*)/m,
    `$1const drawX = x + (dx || 0) * movementProgress;\nconst drawY = y + (dy || 0) * movementProgress;\nctx.save();\nctx.translate(drawX, drawY);\n$2ctx.restore();\n`
  );

  // Fallback add a tick-based interpolation block if render rewrite didn't apply.
  if (updated === text + `\n\n// Smooth movement enhancement\nconst movementLerp = 0.22;\nlet movementProgress = 0;\nlet lastFrameTime = performance.now();\n`) {
    updated += `\n\nfunction updateMovementProgress() {\n  movementProgress += (1 - movementProgress) * movementLerp;\n  if (movementProgress > 0.999) movementProgress = 0;\n}\n`;
  }
}

