const widget = space.chat.transient.get("snake-game");
const source = widget?.source ?? widget?.code ?? widget?.text ?? widget?.content ?? widget;
if (!source || typeof source !== "string") return "No editable source found in transient for snake-game.";

const updated = source
  .replace(/(const CELL_SIZE\s*=\s*\d+;[\s\S]*?)(function|const)\s+render/i, (m) => m)
  .replace(/(ctx\.fillRect\(\s*x\s*,\s*y\s*,\s*CELL_SIZE\s*,\s*CELL_SIZE\s*\);)/g, '$1')
  .replace(/(function\s+render[\s\S]*?)(function\s+gameLoop|const\s+gameLoop)/, (m) => m);

let patched = source;

// Add interpolation helpers if not present
if (!/lerp\(|smoothStep\(|interp/i.test(patched)) {
  patched = patched.replace(
    /(const\s+SNAKE_COLOR[\s\S]*?\n)/,
    `$1
const MOVE_ANIM_MS = 120;
let moveAnimStart = 0;
let prevSnake = null;

function lerp(a, b, t) {
  return a + (b - a) * t;
}

function smoothStep(t) {
  return t * t * (3 - 2 * t);
}

function getInterpolatedSnake() {
  if (!prevSnake || !snake || prevSnake.length !== snake.length) return snake;
  const elapsed = performance.now() - moveAnimStart;
  const t = Math.max(0, Math.min(1, elapsed / MOVE_ANIM_MS));
  const s = smoothStep(t);
  return prevSnake.map((p, i) => ({
    x: lerp(p.x, snake[i].x, s),
    y: lerp(p.y, snake[i].y, s),
  }));
}
`
  );
}

// Capture previous snake before each successful move and arm animation
patched = patched.replace(
  /(function\s+moveSnake\s*\(\)\s*\{[\s\S]*?)(if\s*\(\s*collision\s*\)\s*\{)/,
  `$1prevSnake = snake.map(segment => ({ x: segment.x, y: segment.y })); moveAnimStart = performance.now();
$2`
);

// Ensure rendering uses interpolated positions
patched = patched.replace(
  /(function\s+drawSnake\s*\(\)\s*\{[\s\S]*?for\s*\(\s*const\s+segment\s+of\s+snake\s*\)\s*\{[\s\S]*?ctx\.fillRect\(\s*segment\.x\s*\*\s*CELL_SIZE\s*,\s*segment\.y\s*\*\s*CELL_SIZE\s*,\s*CELL_SIZE\s*,\s*CELL_SIZE\s*\);\s*\}[\s\S]*?\})/,
  `function drawSnake() {
  const segments = getInterpolatedSnake();
  for (let i = 0; i < segments.length; i++) {
    const segment = segments[i];
    const px = segment.x * CELL_SIZE;
    const py = segment.y * CELL_SIZE;
    const pad = i === 0 ? CELL_SIZE * 0.08 : CELL_SIZE * 0.14;
    const size = CELL_SIZE - pad * 2;
    const radius = Math.max(3, size * 0.32);
    roundRect(ctx, px + pad, py + pad, size, size, radius);
    ctx.fillStyle = i === 0 ? '#7CFF6B' : '#4CD95E';
    ctx.fill();
    if (i === 0) {
      ctx.shadowColor = 'rgba(124,255,107,0.35)';
      ctx.shadowBlur = 10;
    }
  }
}`
);

// Add roundRect helper if absent
if (!/function\s+roundRect\s*\(/.test(patched)) {
  patched = patched.replace(
    /(function\s+drawFood[\s\S]*?\n})/,
    `$1

function roundRect(ctx, x, y, width, height, radius) {
  const r = Math.min(radius, width / 2, height / 2);
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + width, y, x + width, y + height, r);
  ctx.arcTo(x + width, y + height, x, y + height, r);
  ctx.arcTo(x, y + height, x, y, r);
  ctx.arcTo(x, y, x + width, y, r);
  ctx.closePath();
}`
  );
}

// Reset animation state on game reset if possible
patched = patched.replace(
  /(function\s+resetGame\s*\(\)\s*\{[\s\S]*?)(\n\})/,
  `$1
  prevSnake = null;
  moveAnimStart = 0;$2`
);

// Fallback: if drawSnake isn't structured as expected, leave source unchanged
if (patched === source) return "Could not safely patch snake animation from current source shape.";

return await space.current.patchWidget("snake-game", { edits: [{ find: source, replace: patched }] });

