const key = "snake-game";
const widget = await space.chat.transient.get(key);
const src = typeof widget === "string" ? widget : (widget?.source ?? widget?.code ?? widget?.content ?? widget?.text ?? JSON.stringify(widget));

const replacements = [
  [
    /const\s+cellSize\s*=\s*([0-9]+)\s*;/,
    (m, n) => `const cellSize = ${n};\nconst moveDuration = 120;`
  ],
  [
    /setInterval\(\s*([^)]+?)\s*,\s*([0-9]+)\s*\)/,
    (m, fn, ms) => `requestAnimationFrame(function loop(now){\n  const t = (now - (window.__snakeLastTick || now));\n  if (t >= ${ms}) { window.__snakeLastTick = now; (${fn.trim()})(); }\n  window.__snakeRaf = requestAnimationFrame(loop);\n});`
  ]
];

let next = src;
let changed = false;
for (const [pattern, repl] of replacements) {
  if (pattern.test(next)) {
    next = next.replace(pattern, repl);
    changed = true;
  }
}

// Fallback: inject smoother interpolation rendering if the code uses grid positions and draw function.
if (!changed) {
  next = next
    .replace(
      /function\s+drawSnake\(([\s\S]*?)\{\n/,
      match => match + `  const interp = (a, b, p) => a + (b - a) * p;\n`
    )
    .replace(
      /(\bctx\.fillRect\()([^;]+)(;)/g,
      (m, pre, args, post) => `${pre}${args}${post}`
    );
}

if (next === src) return "No source changes applied.";
return await space.current.patchWidget("snake-game", { edits: [{ find: src, replace: next }] });

