  [/backgroundColor\s*:\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, "backgroundColor: '#9bbc0f'"],
  [/bg(?:Color)?\s*:\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, "bgColor: '#9bbc0f'"],
  [/fillStyle\s*=\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, "fillStyle = '#9bbc0f'"],
  [/background\s*:\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, "background: '#9bbc0f'"],
  [/['"`]#[0-9a-fA-F]{3,6}['"`]/g, "'#9bbc0f'"]
];

let edited = src;
for (const [re, rep] of replacements) edited = edited.replace(re, rep);

